#!/usr/bin/env bash
# Generated by Agent: IMPLEMENT | Feature: EVOL-020
# ============================================================================
# check-ipp-compliance.sh — PreToolUse hook: block fully-formed first writes
# ============================================================================
# Triggered on Write tool calls.
# Reads stdin JSON: { "tool_name": "Write", "tool_input": { "file_path": "...", "content": "..." } }
#
# Enforces factory-incremental-persistence (IPP) Pillar 1: Skeleton-First Write.
# A first write to a tracked governance artifact MUST be a skeleton — small,
# with <!-- PENDING --> markers, NOT claiming completed sections.
#
# Blocks if:
#   - file does NOT already exist on disk (this is a first write)
#   - AND file path matches a governance artifact pattern
#   - AND content is "fully formed":
#       * has _progress.completed_sections with entries (claims done-on-create), OR
#       * has >= 3 H2 section headers AND 0 "<!-- PENDING -->" markers AND > 150 lines
# ============================================================================

set -euo pipefail

# Read full stdin into variable
INPUT=$(cat)

# Extract file_path and content via python (available in any Claude Code environment)
FILE_PATH=$(echo "$INPUT" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    print(data.get('tool_input', {}).get('file_path', ''))
except Exception:
    print('')
" 2>/dev/null || echo '')

CONTENT=$(echo "$INPUT" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    print(data.get('tool_input', {}).get('content', ''))
except Exception:
    print('')
" 2>/dev/null || echo '')

# Skip if empty path
[ -z "$FILE_PATH" ] && exit 0

# Only applies to first writes — if file already exists, agent is resuming (IPP Pillar 3)
if [ -e "$FILE_PATH" ]; then
  exit 0
fi

# Match tracked governance artifact patterns
BASENAME=$(basename "$FILE_PATH" 2>/dev/null || echo '')
IS_TRACKED=false
case "$FILE_PATH" in
  */docs/spec/*/design.md|\
  */docs/spec/*/test_plan.md|\
  */docs/spec/*/dev_plan.md|\
  */docs/spec/*/increment_plan.md|\
  */docs/spec/*/slice_map.md|\
  */docs/spec/*/spec.feature|\
  */docs/spec/*/user_journey.md|\
  */docs/spec/*/user_journey.integration.md|\
  */docs/spec/*/mock.html|\
  */docs/spec/*/devops_plan.md|\
  */docs/spec/*/technical_due.md|\
  */docs/setup.md)
    IS_TRACKED=true
    ;;
esac

# Also match qa_report*.md and technical_due*.md by basename (variants exist)
if [ "$IS_TRACKED" = false ]; then
  case "$BASENAME" in
    qa_report*.md|technical_due*.md)
      IS_TRACKED=true
      ;;
  esac
fi

if [ "$IS_TRACKED" = false ]; then
  exit 0
fi

# Signal 1: _progress.completed_sections non-empty on first write = violation
# The frontmatter is YAML between --- markers. Look for completed_sections: [...] with content.
if echo "$CONTENT" | python3 -c "
import sys, re
content = sys.stdin.read()
# Extract YAML frontmatter
m = re.match(r'^---\n(.*?)\n---', content, re.DOTALL)
if not m:
    sys.exit(0)
fm = m.group(1)
# Look for completed_sections under _progress
in_progress = False
for line in fm.split('\n'):
    stripped = line.strip()
    if stripped.startswith('_progress:'):
        in_progress = True
        continue
    if in_progress and line and not line.startswith(' ') and not line.startswith('\t'):
        in_progress = False
    if in_progress and 'completed_sections' in stripped:
        # Check if list has entries (not [] and not empty)
        after = stripped.split(':', 1)[1].strip()
        if after and after != '[]' and after != '\"\"' and after != \"''\":
            sys.exit(42)  # populated inline list
        # Check next lines for dash entries
        idx = fm.split('\n').index(line)
        for nxt in fm.split('\n')[idx+1:]:
            if nxt.strip().startswith('- '):
                sys.exit(42)
            if nxt and not nxt.startswith(' ') and not nxt.startswith('\t'):
                break
sys.exit(0)
" 2>/dev/null; then
  :  # no violation from signal 1
else
  RC=$?
  if [ "$RC" = "42" ]; then
    echo "BLOCKED: IPP violation on first write to '$BASENAME'."
    echo "  _progress.completed_sections claims sections done, but this is the creation write."
    echo "  Skeleton-First Write (IPP Pillar 1) requires an empty completed_sections[] on creation."
    echo "  See: .claude/skills/factory-incremental-persistence/SKILL.md § Pillar 1."
    exit 1
  fi
fi

# Signal 2: fully-formed body (>=3 H2 headers, 0 PENDING markers, > 150 lines)
H2_COUNT=$(echo "$CONTENT" | grep -c '^##[^#]' 2>/dev/null || true)
PENDING_COUNT=$(echo "$CONTENT" | grep -c '<!-- PENDING -->' 2>/dev/null || true)
LINE_COUNT=$(echo "$CONTENT" | wc -l | tr -d ' ')
H2_COUNT=${H2_COUNT:-0}
PENDING_COUNT=${PENDING_COUNT:-0}

if [ -n "${H2_COUNT:-}" ] && [ -n "${PENDING_COUNT:-}" ] && [ -n "${LINE_COUNT:-}" ] \
   && [ "$H2_COUNT" -ge 3 ] && [ "$PENDING_COUNT" -eq 0 ] && [ "$LINE_COUNT" -gt 150 ]; then
  echo "BLOCKED: IPP violation on first write to '$BASENAME'."
  echo "  File has $H2_COUNT H2 sections, $LINE_COUNT lines, and 0 '<!-- PENDING -->' markers."
  echo "  Skeleton-First Write (IPP Pillar 1) requires an initial skeleton with <!-- PENDING --> placeholders,"
  echo "  then section-atomic saves (Pillar 2) — not one big terminal write."
  echo "  See: .claude/skills/factory-incremental-persistence/SKILL.md § Pillars 1-2."
  exit 1
fi

# Legitimate first write — drop a session-scoped marker so the next
# UserPromptSubmit (governance-onprompt.sh) can inject an <ipp-reminder>
# teaching block. The marker is best-effort: SESSION_ID may be empty in
# environments where the PreToolUse payload omits it, in which case we
# write to a session-less marker that still survives until the next prompt.
SESSION_ID=$(echo "$INPUT" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    print(data.get('session_id', ''))
except Exception:
    print('')
" 2>/dev/null || echo '')

STATE_DIR=".claude/state"
mkdir -p "$STATE_DIR" 2>/dev/null || exit 0

SESSION_ID_SAFE=$(printf '%s' "$SESSION_ID" | tr -cd 'A-Za-z0-9_-')
if [ -n "$SESSION_ID_SAFE" ]; then
  MARKER="${STATE_DIR}/ipp-first-write-${SESSION_ID_SAFE}.marker"
else
  MARKER="${STATE_DIR}/ipp-first-write.marker"
fi

# Repo-relative path for marker entry — strip absolute prefix when possible.
NORM_PATH="$FILE_PATH"
REPO_ROOT=$(pwd 2>/dev/null || echo '')
if [ -n "$REPO_ROOT" ]; then
  case "$NORM_PATH" in
    "$REPO_ROOT/"*) NORM_PATH="${NORM_PATH#$REPO_ROOT/}" ;;
  esac
fi

{
  if [ -f "$MARKER" ]; then cat "$MARKER"; fi
  printf '%s\n' "$NORM_PATH"
} | sort -u > "${MARKER}.tmp" 2>/dev/null && mv "${MARKER}.tmp" "$MARKER" 2>/dev/null || true

exit 0
